14	// AdaptiveMinTierThreshold is the cheap-tier trailing success rate below which
15	// AdaptiveMinTier recommends skipping the cheap tier. At 0.20, four out of
16	// five cheap-tier attempts must fail before the cheap tier is suppressed.
17	const AdaptiveMinTierThreshold = 0.20
18	
19	// AdaptiveMinTierMinSamples is the minimum number of cheap-tier attempts
20	// required in the window before the cheap-tier success rate is considered
21	// statistically meaningful. Below this the cheap tier is kept in-range so
22	// we do not starve it on insufficient evidence.
23	const AdaptiveMinTierMinSamples = 3
24	
25	// SuccessStatus mirrors agent.ExecuteBeadStatusSuccess. The agent package's
26	// TestEscalatableStatusesMatchAgentVocab guard catches drift if either side
27	// renames. Defined locally so escalation does not import agent.
28	const SuccessStatus = "success"
29	
30	// EscalatableStatuses is the set of executor status strings that warrant
31	// retrying with a higher tier. Mirrors a subset of agent.ExecuteBeadStatus*
32	// strings; the agent package has a TestEscalatableStatusesMatchAgentVocab
33	// guard (see agent/tier_escalation_alignment_test.go) to catch drift.
34	var EscalatableStatuses = map[string]bool{
35		"execution_failed":             true,
36		"post_run_check_failed":        true,
37		"land_conflict":                true,
38		"structural_validation_failed": true,
39	}
40	
41	// AdaptiveMinTierResult carries the recommendation from AdaptiveMinTier along
42	// with the observed cheap-tier sample count and success rate so callers can
43	// emit a log line explaining the decision.
44	type AdaptiveMinTierResult struct {
45		// Tier is the recommended minimum tier: TierCheap when the cheap tier is
46		// viable, TierStandard when cheap-tier success is below the threshold.
47		Tier ModelTier
48		// CheapAttempts is the number of cheap-tier attempts observed in the
49		// window. Zero when no cheap-tier history was found.
50		CheapAttempts int
51		// CheapSuccessRate is CheapSuccesses / CheapAttempts, or 0 when
52		// CheapAttempts is 0.
53		CheapSuccessRate float64
54		// Skipped is true when the recommendation is to skip the cheap tier.
55		Skipped bool
56	}
57	
58	// taskResultLite is a minimal projection of agent.ExecuteBeadResult that
59	// captures only the fields AdaptiveMinTier needs. Defined locally so the
60	// escalation package does not depend on the agent package.
61	type taskResultLite struct {
62		Harness string `json:"harness"`
63		Model   string `json:"model"`
64		Outcome string `json:"outcome"`
65	}
66	
67	// TierResolver resolves a (harness, tier) pair to a concrete model name. This
68	// is normally agent.ResolveModelTier; injected as a parameter so the
69	// escalation package does not import agent.
70	type TierResolver func(harness string, tier ModelTier) string
71	
72	// AdaptiveMinTier inspects the most recent `window` entries under
73	// workingDir/.ddx/executions/*/result.json, computes the cheap-tier trailing
74	// success rate, and returns a recommendation:
75	//
76	//   - When cheap-tier success rate < AdaptiveMinTierThreshold (and at least
77	//     AdaptiveMinTierMinSamples cheap attempts were observed), returns
78	//     TierStandard with Skipped=true.
79	//   - Otherwise returns TierCheap with Skipped=false.
80	//
81	// A tier is identified by resolving (harness, model) back through the
82	// supplied resolver — attempts whose harness/model do not match any known
83	// tier mapping are ignored for the purpose of this calculation. When
84	// workingDir has no executions directory (e.g. a fresh project), the cheap
85	// tier is kept in-range so a first run is not artificially restricted.
86	func AdaptiveMinTier(workingDir string, window int, resolver TierResolver) AdaptiveMinTierResult {
87		execRoot := filepath.Join(workingDir, ".ddx", "executions")
88		entries, err := os.ReadDir(execRoot)
89		if err != nil {
90			return AdaptiveMinTierResult{Tier: TierCheap}
91		}
92	
93		names := make([]string, 0, len(entries))
94		for _, entry := range entries {
95			if entry.IsDir() {
96				names = append(names, entry.Name())
97			}
98		}
99		// Directory names are sortable timestamps (YYYYMMDDTHHMMSS-<hash>), so
100		// lexicographic sort is chronological.
101		sort.Strings(names)
102	
103		// Collect usable attempts, then truncate to the most recent `window`.
104		type attempt struct {
105			tier    ModelTier
106			success bool
107		}
108		collected := make([]attempt, 0, len(names))
109		for _, name := range names {
110			resultPath := filepath.Join(execRoot, name, "result.json")
111			raw, err := os.ReadFile(resultPath)
112			if err != nil {
113				continue
114			}
115			var res taskResultLite
116			if err := json.Unmarshal(raw, &res); err != nil {
117				continue
118			}
119			if res.Harness == "" {
120				continue
121			}
122			tier := classifyAttemptTier(res.Harness, res.Model, resolver)
123			if tier == "" {
124				continue
125			}
126			collected = append(collected, attempt{
127				tier:    tier,
128				success: res.Outcome == "task_succeeded",
129			})
130		}
131		if window > 0 && len(collected) > window {
132			collected = collected[len(collected)-window:]
133		}
134	
135		var cheapAttempts, cheapSuccesses int
136		for _, a := range collected {
137			if a.tier == TierCheap {
138				cheapAttempts++
139				if a.success {
140					cheapSuccesses++
141				}
142			}
143		}
144	
145		result := AdaptiveMinTierResult{Tier: TierCheap, CheapAttempts: cheapAttempts}
146		if cheapAttempts > 0 {
147			result.CheapSuccessRate = float64(cheapSuccesses) / float64(cheapAttempts)
148		}
149		if cheapAttempts >= AdaptiveMinTierMinSamples && result.CheapSuccessRate < AdaptiveMinTierThreshold {
150			result.Tier = TierStandard
151			result.Skipped = true
152		}
153		return result
154	}
155	
156	// classifyAttemptTier returns the ModelTier that corresponds to a (harness,
157	// model) pair by reverse-lookup against the supplied resolver. Returns ""
158	// when no tier in TierOrder matches — e.g. an ad-hoc model pin not present
159	// in the catalog, which should not contribute to tier-level analytics. A
160	// nil resolver is treated as no-match for every tier.
161	func classifyAttemptTier(harness, model string, resolver TierResolver) ModelTier {
162		if harness == "" || resolver == nil {
163			return ""
164		}
165		for _, tier := range TierOrder {
166			if resolver(harness, tier) == model {
167				return tier
168			}
169		}
170		return ""
171	}
172	
173	// TierOrder defines the escalation sequence from cheapest to most capable.
174	var TierOrder = []ModelTier{TierCheap, TierStandard, TierSmart}
175	
176	// ProviderCooldownDuration is how long an unhealthy harness is skipped before
177	// re-probing. Five minutes gives most transient errors time to resolve without
178	// locking out a provider for too long.
179	//
180	// Per-harness cooldown tracking moved to the upstream agent service in v0.8.0:
181	// callers record failures via svc.RecordRouteAttempt and read cooldown state
182	// via svc.RouteStatus's RouteCandidateStatus.Healthy (ddx-7bc0c8d5).
183	const ProviderCooldownDuration = 5 * time.Minute
184	
185	// tierIndex returns the position of t in TierOrder, or -1 if not found.
186	func tierIndex(t ModelTier) int {
187		for i, tier := range TierOrder {
188			if tier == t {
189				return i
190			}
191		}
192		return -1
193	}
194	
195	// TiersInRange returns the subset of TierOrder from minTier to maxTier inclusive.
196	// Empty string defaults to the global extremes (cheap and smart).
197	// If minTier > maxTier in the order, an empty slice is returned.
198	func TiersInRange(minTier, maxTier ModelTier) []ModelTier {
199		if minTier == "" {
200			minTier = TierCheap
201		}
202		if maxTier == "" {
203			maxTier = TierSmart
204		}
205		minIdx := tierIndex(minTier)
206		maxIdx := tierIndex(maxTier)
207		if minIdx < 0 {
208			minIdx = 0
209		}
210		if maxIdx < 0 {
211			maxIdx = len(TierOrder) - 1
212		}
213		if minIdx > maxIdx {
214			return nil
215		}
216		// Return a copy so callers cannot mutate TierOrder.
217		out := make([]ModelTier, maxIdx-minIdx+1)
218		copy(out, TierOrder[minIdx:maxIdx+1])
219		return out
220	}
221	
222	// ShouldEscalate reports whether status warrants escalating to the next tier.
223	// Structural failures (e.g. validation errors) do not escalate because a
224	// smarter model cannot fix a malformed prompt or corrupted bead state.
225	func ShouldEscalate(status string) bool {
226		return EscalatableStatuses[status]
227	}
