183	func (r *Runner) recordRoutingOutcome(result *Result, elapsed time.Duration, opts RunArgs) {
184		if r == nil || result == nil || r.Config.SessionLogDir == "" {
185			return
186		}
187	
188		harness, _ := r.registry.Get(result.Harness)
189		canonicalTarget := result.Model
190		if canonicalTarget == "" {
191			canonicalTarget = opts.Model
192		}
193		if canonicalTarget == "" && harness.DefaultModel != "" {
194			canonicalTarget = harness.DefaultModel
195		}
196		if canonicalTarget == "" {
197			canonicalTarget = result.Harness
198		}
199	
200		outcome := RoutingOutcome{
201			Harness:         result.Harness,
202			Surface:         harness.Surface,
203			CanonicalTarget: canonicalTarget,
204			Model:           result.Model,
205			ObservedAt:      time.Now().UTC(),
206			Success:         result.ExitCode == 0 && result.Error == "",
207			LatencyMS:       int(elapsed.Milliseconds()),
208			InputTokens:     result.InputTokens,
209			OutputTokens:    result.OutputTokens,
210			CostUSD:         result.CostUSD,
211			NativeSessionID: result.AgentSessionID,
212		}
213	
214		if opts.Correlation != nil {
215			outcome.TraceID = opts.Correlation["trace_id"]
216			outcome.SpanID = opts.Correlation["span_id"]
217			if outcome.NativeSessionID == "" {
218				outcome.NativeSessionID = opts.Correlation["native_session_id"]
219			}
220			if outcome.NativeLogRef == "" {
221				outcome.NativeLogRef = opts.Correlation["native_log_ref"]
222			}
223		}
224	
225		_ = NewRoutingMetricsStore(r.Config.SessionLogDir).AppendOutcome(outcome)
226	}
