228	func parseWindowMinutes(raw string) int {
229		raw = strings.TrimSpace(raw)
230		if raw == "" {
231			return 0
232		}
233	
234		fields := strings.Fields(raw)
235		if len(fields) == 1 {
236			raw = fields[0]
237		}
238	
239		numRe := strings.Builder{}
240		for _, r := range raw {
241			if r >= '0' && r <= '9' {
242				numRe.WriteRune(r)
243			} else {
244				break
245			}
246		}
247		if numRe.Len() == 0 {
248			return 0
249		}
250		n, err := strconv.Atoi(numRe.String())
251		if err != nil {
252			return 0
253		}
254	
255		lower := strings.ToLower(raw)
256		switch {
257		case strings.Contains(lower, "day"):
258			return n * 24 * 60
259		case strings.Contains(lower, "hour"), strings.HasSuffix(lower, "h"):
260			return n * 60
261		case strings.Contains(lower, "min"), strings.HasSuffix(lower, "m"):
262			return n
263		default:
264			return n
265		}
266	}
