183	func (f *CommandFactory) newAgentRouteStatusCommand() *cobra.Command {
184		cmd := &cobra.Command{
185			Use:   "route-status",
186			Short: "Show routing table, recent decisions, and active health cooldowns",
187			Long: `Shows the current provider routing state, recent routing decisions, and
188	any health cooldowns currently in effect.
189	
190	Uses the ddx-agent Service.RouteStatus API. Requires model routes to be
191	configured in .agent/config.yaml.
192	
193	Examples:
194	  ddx agent route-status
195	  ddx agent route-status --model qwen3.5-27b
196	  ddx agent route-status --json`,
197			Args: cobra.NoArgs,
198			RunE: func(cmd *cobra.Command, args []string) error {
199				model, _ := cmd.Flags().GetString("model")
200				asJSON, _ := cmd.Flags().GetBool("json")
201	
202				svc, err := agent.NewServiceFromWorkDir(f.WorkingDir)
203				if err != nil {
204					return fmt.Errorf("loading agent config: %w", err)
205				}
206	
207				ctx := context.Background()
208				report, err := svc.RouteStatus(ctx)
209				if err != nil {
210					return fmt.Errorf("getting route status: %w", err)
211				}
212	
213				// Filter by --model flag if specified.
214				if model != "" {
215					found := false
216					for _, r := range report.Routes {
217						if r.Model == model {
218							found = true
219							break
220						}
221					}
222					if !found {
223						return fmt.Errorf("no route configured for model key %q — check .agent/config.yaml", model)
224					}
225					filtered := report.Routes[:0]
226					for _, r := range report.Routes {
227						if r.Model == model {
228							filtered = append(filtered, r)
229						}
230					}
231					report.Routes = filtered
232				}
233	
234				if len(report.Routes) == 0 {
235					if !asJSON {
236						fmt.Fprintln(cmd.OutOrStdout(), "No model routes configured in .agent/config.yaml.")
237						fmt.Fprintln(cmd.OutOrStdout(), "Use --model <route-key> or configure model_routes in .agent/config.yaml.")
238					} else {
239						enc := json.NewEncoder(cmd.OutOrStdout())
240						enc.SetIndent("", "  ")
241						return enc.Encode(routeStatusJSON{})
242					}
243					return nil
244				}
245	
246				// Load recent routing decisions from two complementary sources:
247				//
248				//  1. RoutingMetricsStore — harness-level analytics (latency, success
249				//     rate) for every agent run, stored in routing-outcomes.jsonl.
250				//  2. kind:routing bead events — execution provenance per bead (which
251				//     provider/model was selected and why), tied to a specific bead ID.
252				var recentDecisions []recentRoutingDecision
253	
254				if logDir := agent.SessionLogDirForWorkDir(f.WorkingDir); logDir != "" {
255					store := agent.NewRoutingMetricsStore(logDir)
256					outcomes, _ := store.ReadOutcomes()
257					for _, o := range outcomes {
258						recentDecisions = append(recentDecisions, recentRoutingDecision{
259							ObservedAt:   o.ObservedAt,
260							Source:       "metrics-store",
261							Harness:      o.Harness,
262							Provider:     o.CanonicalTarget,
263							Model:        o.Model,
264							Success:      o.Success,
265							SuccessKnown: true,
266							LatencyMS:    o.LatencyMS,
267						})
268					}
269				}
270	
271				// Merge kind:routing bead evidence entries.
272				recentDecisions = append(recentDecisions, beadRoutingDecisionsFromStore(f.WorkingDir)...)
273	
274				// Sort by time and take the last N.
275				sort.Slice(recentDecisions, func(i, j int) bool {
276					return recentDecisions[i].ObservedAt.Before(recentDecisions[j].ObservedAt)
277				})
278				const maxRecent = 10
279				if len(recentDecisions) > maxRecent {
280					recentDecisions = recentDecisions[len(recentDecisions)-maxRecent:]
281				}
282	
283				// Collect active cooldowns across all routes from the report.
284				type cooldownEntry struct {
285					route         string
286					provider      string
287					failedAt      time.Time
288					cooldownUntil time.Time
289				}
290				var activeCooldowns []cooldownEntry
291				seenCooldownKeys := make(map[string]struct{})
292				for _, entry := range report.Routes {
293					for _, cand := range entry.Candidates {
294						if cand.Cooldown != nil && time.Now().Before(cand.Cooldown.Until) {
295							ck := entry.Model + "|" + cand.Provider
296							if _, seen := seenCooldownKeys[ck]; !seen {
297								seenCooldownKeys[ck] = struct{}{}
298								// FailedAt is not directly available; use Until minus a best-effort estimate.
299								// We record Until and leave FailedAt as zero for cooldowns from the service.
300								activeCooldowns = append(activeCooldowns, cooldownEntry{
301									route:         entry.Model,
302									provider:      cand.Provider,
303									cooldownUntil: cand.Cooldown.Until,
304								})
305							}
306						}
307					}
308				}
309				sort.Slice(activeCooldowns, func(i, j int) bool {
310					return activeCooldowns[i].route < activeCooldowns[j].route
311				})
312	
313				if asJSON {
314					payload := routeStatusJSON{}
315					for _, entry := range report.Routes {
316						rj := routeStatusRouteJSON{
317							RouteKey: entry.Model,
318							Strategy: entry.Strategy,
319						}
320						for _, cand := range entry.Candidates {
321							cj := routeStatusCandidateJSON{
322								Provider:      cand.Provider,
323								Model:         cand.Model,
324								Healthy:       cand.Healthy,
325								AvgDurationMs: cand.RecentLatencyMS,
326								Reliability:   cand.ProviderReliabilityRate,
327							}
328							if cand.Cooldown != nil && !cand.Cooldown.Until.IsZero() {
329								cj.InCooldown = true
330								cj.CooldownUntil = cand.Cooldown.Until.UTC().Format(time.RFC3339)
331								cj.Reason = fmt.Sprintf("cooldown until %s", cand.Cooldown.Until.Format(time.RFC3339))
332							}
333							rj.Candidates = append(rj.Candidates, cj)
334							if cand.Healthy && rj.SelectedProvider == "" {
335								rj.SelectedProvider = cand.Provider
336								rj.SelectedModel = cand.Model
337							}
338						}
339						payload.Routes = append(payload.Routes, rj)
340					}
341					for _, d := range recentDecisions {
342						jd := routeStatusDecisionJSON{
343							ObservedAt:  d.ObservedAt.UTC().Format(time.RFC3339),
344							Source:      d.Source,
345							BeadID:      d.BeadID,
346							Harness:     d.Harness,
347							Provider:    d.Provider,
348							Model:       d.Model,
349							RouteReason: d.RouteReason,
350						}
351						if d.Source == "metrics-store" {
352							jd.CanonicalTarget = d.Provider
353							jd.Success = d.Success
354							jd.LatencyMs = d.LatencyMS
355						}
356						payload.RecentDecisions = append(payload.RecentDecisions, jd)
357					}
358					for _, c := range activeCooldowns {
359						cd := routeStatusCooldownJSON{
360							Route:         c.route,
361							Provider:      c.provider,
362							CooldownUntil: c.cooldownUntil.UTC().Format(time.RFC3339),
363						}
364						if !c.failedAt.IsZero() {
365							cd.FailedAt = c.failedAt.UTC().Format(time.RFC3339)
366						}
367						payload.ActiveCooldowns = append(payload.ActiveCooldowns, cd)
368					}
369					enc := json.NewEncoder(cmd.OutOrStdout())
370					enc.SetIndent("", "  ")
371					return enc.Encode(payload)
372				}
373	
374				out := cmd.OutOrStdout()
375	
376				// --- Section 1: Route Table ---
377				for i, entry := range report.Routes {
378					if i > 0 {
379						fmt.Fprintln(out)
380					}
381	
382					selectedProvider := ""
383					selectedModel := ""
384					for _, cand := range entry.Candidates {
385						if cand.Healthy {
386							selectedProvider = cand.Provider
387							selectedModel = cand.Model
388							break
389						}
390					}
391	
392					strategy := entry.Strategy
393					if strategy == "" {
394						strategy = "first-available"
395					}
396	
397					fmt.Fprintf(out, "Route: %s\n", entry.Model)
398					fmt.Fprintf(out, "Strategy: %s\n", strategy)
399					if selectedProvider != "" {
400						fmt.Fprintf(out, "Selected: %s (%s)\n", selectedProvider, selectedModel)
401					} else {
402						fmt.Fprintf(out, "Selected: (none — all candidates down or in cooldown)\n")
403					}
404	
405					fmt.Fprintf(out, "%-12s %-32s %-10s %-10s %-10s %-12s %s\n",
406						"PROVIDER", "MODEL", "HEALTH", "SCORE", "RELIABILITY", "LATENCY_MS", "REASON")
407					for _, cand := range entry.Candidates {
408						health := "available"
409						reason := ""
410						if cand.Cooldown != nil && !cand.Cooldown.Until.IsZero() {
411							health = "cooldown"
412							reason = fmt.Sprintf("cooldown until %s", cand.Cooldown.Until.Format(time.RFC3339))
413						} else if !cand.Healthy {
414							health = "down"
415						}
416						fmt.Fprintf(out, "%-12s %-32s %-10s %-10.3f %-10.2f %-12.0f %s\n",
417							cand.Provider,
418							truncateRouteStr(cand.Model, 32),
419							health,
420							0.0, // Score not provided by RouteStatusReport
421							cand.ProviderReliabilityRate,
422							cand.RecentLatencyMS,
423							reason,
424						)
425					}
426				}
427	
428				// --- Section 2: Recent Routing Decisions ---
429				fmt.Fprintln(out)
430				fmt.Fprintf(out, "Recent Routing Decisions (last %d)\n", len(recentDecisions))
431				fmt.Fprintf(out, "%s\n", strings.Repeat("-", 90))
432				if len(recentDecisions) == 0 {
433					fmt.Fprintln(out, "  (no recorded decisions)")
434				} else {
435					fmt.Fprintf(out, "%-22s %-14s %-24s %-20s %-6s %s\n",
436						"OBSERVED_AT", "SOURCE", "PROVIDER", "MODEL", "OK", "BEAD")
437					for _, d := range recentDecisions {
438						ok := "-"
439						if d.SuccessKnown {
440							ok = "no"
441							if d.Success {
442								ok = "yes"
443							}
444						}
445						fmt.Fprintf(out, "%-22s %-14s %-24s %-20s %-6s %s\n",
446							d.ObservedAt.UTC().Format("2006-01-02T15:04:05Z"),
447							d.Source,
448							truncateRouteStr(d.Provider, 24),
449							truncateRouteStr(d.Model, 20),
450							ok,
451							d.BeadID,
452						)
453					}
454				}
455	
456				// --- Section 3: Active Health Cooldowns ---
457				fmt.Fprintln(out)
458				fmt.Fprintf(out, "Active Health Cooldowns\n")
459				fmt.Fprintf(out, "%s\n", strings.Repeat("-", 70))
460				if len(activeCooldowns) == 0 {
461					fmt.Fprintln(out, "  (none)")
462				} else {
463					fmt.Fprintf(out, "%-20s %-12s %-24s %s\n",
464						"ROUTE", "PROVIDER", "FAILED_AT", "COOLDOWN_UNTIL")
465					for _, c := range activeCooldowns {
466						failedAtStr := "-"
467						if !c.failedAt.IsZero() {
468							failedAtStr = c.failedAt.UTC().Format("2006-01-02T15:04:05Z")
469						}
470						fmt.Fprintf(out, "%-20s %-12s %-24s %s\n",
471							truncateRouteStr(c.route, 20),
472							c.provider,
473							failedAtStr,
474							c.cooldownUntil.UTC().Format("2006-01-02T15:04:05Z"),
475						)
476					}
477				}
478	
479				return nil
480			},
481		}
482		cmd.Flags().String("model", "", "Requested model route key (e.g. qwen3.5-27b)")
483		cmd.Flags().Bool("json", false, "Output JSON")
484		return cmd
485	}
