173	// TierOrder defines the escalation sequence from cheapest to most capable.
174	var TierOrder = []ModelTier{TierCheap, TierStandard, TierSmart}
175	
176	// ProviderCooldownDuration is how long an unhealthy harness is skipped before
177	// re-probing. Five minutes gives most transient errors time to resolve without
178	// locking out a provider for too long.
179	//
180	// Per-harness cooldown tracking moved to the upstream agent service in v0.8.0:
181	// callers record failures via svc.RecordRouteAttempt and read cooldown state
182	// via svc.RouteStatus's RouteCandidateStatus.Healthy (ddx-7bc0c8d5).
183	const ProviderCooldownDuration = 5 * time.Minute
