195	// TiersInRange returns the subset of TierOrder from minTier to maxTier inclusive.
196	// Empty string defaults to the global extremes (cheap and smart).
197	// If minTier > maxTier in the order, an empty slice is returned.
198	func TiersInRange(minTier, maxTier ModelTier) []ModelTier {
199		if minTier == "" {
200			minTier = TierCheap
201		}
202		if maxTier == "" {
203			maxTier = TierSmart
204		}
205		minIdx := tierIndex(minTier)
206		maxIdx := tierIndex(maxTier)
207		if minIdx < 0 {
208			minIdx = 0
209		}
210		if maxIdx < 0 {
211			maxIdx = len(TierOrder) - 1
212		}
213		if minIdx > maxIdx {
214			return nil
215		}
216		// Return a copy so callers cannot mutate TierOrder.
217		out := make([]ModelTier, maxIdx-minIdx+1)
218		copy(out, TierOrder[minIdx:maxIdx+1])
219		return out
220	}
