269	// BuildEscalationSummary computes the summary body from the ordered list of
270	// attempts. winningTier is the string of the tier whose attempt succeeded;
271	// pass "" when the escalation was exhausted, in which case winning_tier is
272	// set to EscalationWinningExhausted. Total cost is the sum of all attempt
273	// costs; wasted cost is the sum of attempts whose status is not
274	// SuccessStatus.
275	func BuildEscalationSummary(attempts []TierAttemptRecord, winningTier string) EscalationSummary {
276		out := EscalationSummary{
277			TiersAttempted: append([]TierAttemptRecord{}, attempts...),
278			WinningTier:    winningTier,
279		}
280		if out.WinningTier == "" {
281			out.WinningTier = EscalationWinningExhausted
282		}
283		for _, a := range attempts {
284			out.TotalCostUSD += a.CostUSD
285			if a.Status != SuccessStatus {
286				out.WastedCostUSD += a.CostUSD
287			}
288		}
289		return out
290	}
