// AdaptiveTierStats describes the trailing-window observation for one tier.
type AdaptiveTierStats struct {
	Attempts                int
	Successes               int
	SuccessRate             float64
	ExcludedRoutingFailures int
}

// AdaptiveExcludedFailureModes is the set of FailureMode values whose
// attempts are recorded but NOT counted toward the trailing success rate.
// These are routing- or configuration-level failures that never reached an
// actual model invocation, so they should not damage a tier's reputation.
//
// Mirrors a subset of agent.FailureMode* constants. The agent package keeps
// the canonical names; this set is duplicated here so the escalation
// package does not import agent. The `routing_error` value is checked for
// drift by agent.TestRoutingFailureModeMatchesEscalationVocab.
var AdaptiveExcludedFailureModes = map[string]bool{
	"routing_error": true,
}

// taskResultLite is a minimal projection of agent.ExecuteBeadResult that
