	Outcome     string `json:"outcome"`
	FailureMode string `json:"failure_mode"`
}

// AdaptiveStateDir is the per-project directory where the adaptive min-tier
// state file lives, relative to the project root.
const AdaptiveStateDir = ".ddx/agent-state"

// AdaptiveStateFile is the JSON file inside AdaptiveStateDir that stores
// the reset checkpoint and reset metadata.
const AdaptiveStateFile = "adaptive-min-tier.json"

// AdaptiveState is the on-disk schema of AdaptiveStateFile. ResetAt is the
// lexicographic high-water mark — execution directories whose name sorts
// less than or equal to ResetAt are excluded from AdaptiveMinTier
// computations. Execution directories use the YYYYMMDDTHHMMSS-<hash>
// naming convention, so ResetAt is normally written as the timestamp at
// which the reset was issued.
type AdaptiveState struct {
	ResetAt     string `json:"reset_at,omitempty"`
	ResetBy     string `json:"reset_by,omitempty"`
	ResetReason string `json:"reset_reason,omitempty"`
}

// AdaptiveStatePath returns the absolute path to the adaptive state file
// for workingDir. The file may not exist; callers should treat ENOENT as
// "no reset recorded".
func AdaptiveStatePath(workingDir string) string {
	return filepath.Join(workingDir, AdaptiveStateDir, AdaptiveStateFile)
}

// LoadAdaptiveState reads the adaptive state file. A missing file returns
// the zero AdaptiveState and a nil error so callers can treat "no reset
// recorded" identically to "no state file yet".
func LoadAdaptiveState(workingDir string) (AdaptiveState, error) {
	raw, err := os.ReadFile(AdaptiveStatePath(workingDir))
	if err != nil {
		if os.IsNotExist(err) {
			return AdaptiveState{}, nil
		}
		return AdaptiveState{}, err
	}
	var state AdaptiveState
	if err := json.Unmarshal(raw, &state); err != nil {
		return AdaptiveState{}, err
	}
	return state, nil
}

// WriteAdaptiveState writes state to AdaptiveStateFile under workingDir,
// creating the parent directory if needed. Used by `ddx agent route-status
// reset` to record a new reset checkpoint.
func WriteAdaptiveState(workingDir string, state AdaptiveState) error {
	path := AdaptiveStatePath(workingDir)
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	raw, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(path, raw, 0o644)
}

