func AdaptiveMinTier(workingDir string, window int, resolver TierResolver) AdaptiveMinTierResult {
	state, _ := LoadAdaptiveState(workingDir)
	result := AdaptiveMinTierResult{
		Tier:    TierCheap,
		Window:  window,
		ResetAt: state.ResetAt,
		PerTier: emptyAdaptiveTierStats(),
	}

	execRoot := filepath.Join(workingDir, ".ddx", "executions")
	entries, err := os.ReadDir(execRoot)
	if err != nil {
		return result
	}

	names := make([]string, 0, len(entries))
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		name := entry.Name()
		// Reset checkpoint: any execution dir whose name sorts at or below
		// ResetAt is excluded so a fresh evaluation can start without prior
		// trailing-window verdicts carrying over (AC1, AC5).
		if state.ResetAt != "" && name <= state.ResetAt {
			continue
		}
		names = append(names, name)
	}
	// Directory names are sortable timestamps (YYYYMMDDTHHMMSS-<hash>), so
	// lexicographic sort is chronological.
	sort.Strings(names)

	// Collect usable attempts, then truncate to the most recent `window`.
	type attempt struct {
		tier            ModelTier
		success         bool
		excludedRouting bool
	}
	collected := make([]attempt, 0, len(names))
	for _, name := range names {
		resultPath := filepath.Join(execRoot, name, "result.json")
		raw, err := os.ReadFile(resultPath)
		if err != nil {
			continue
		}
		var res taskResultLite
		if err := json.Unmarshal(raw, &res); err != nil {
			continue
		}
		if res.Harness == "" {
			continue
		}
		tier := classifyAttemptTier(res.Harness, res.Model, resolver)
		if tier == "" {
			continue
		}
		collected = append(collected, attempt{
			tier:            tier,
			success:         res.Outcome == "task_succeeded",
			excludedRouting: AdaptiveExcludedFailureModes[res.FailureMode],
		})
	}
	if window > 0 && len(collected) > window {
		collected = collected[len(collected)-window:]
	}

	for _, a := range collected {
		stats := result.PerTier[a.tier]
		if a.excludedRouting {
			stats.ExcludedRoutingFailures++
			result.PerTier[a.tier] = stats
			continue
		}
		stats.Attempts++
		if a.success {
			stats.Successes++
		}
		result.PerTier[a.tier] = stats
	}
	for tier, stats := range result.PerTier {
		if stats.Attempts > 0 {
			stats.SuccessRate = float64(stats.Successes) / float64(stats.Attempts)
		}
		result.PerTier[tier] = stats
	}

	cheap := result.PerTier[TierCheap]
	result.CheapAttempts = cheap.Attempts
	result.CheapSuccessRate = cheap.SuccessRate
	result.ExcludedRoutingFailures = cheap.ExcludedRoutingFailures
	if cheap.Attempts >= AdaptiveMinTierMinSamples && cheap.SuccessRate < AdaptiveMinTierThreshold {
		result.Tier = TierStandard
		result.Skipped = true
	}
	return result
}

