			state := escalation.AdaptiveState{
				ResetAt:     resetAt,
				ResetBy:     actor,
				ResetReason: reason,
			}
			if err := escalation.WriteAdaptiveState(workDir, state); err != nil {
				return fmt.Errorf("writing adaptive state: %w", err)
			}

			if asJSON {
				enc := json.NewEncoder(out)
				enc.SetIndent("", "  ")
				return enc.Encode(struct {
					ResetAt     string `json:"reset_at"`
					StateFile   string `json:"state_file"`
					Scope       string `json:"scope"`
					Reason      string `json:"reason,omitempty"`
					NotTouched  []string `json:"not_touched"`
				}{
					ResetAt:    resetAt,
					StateFile:  statePath,
					Scope:      coalesceScope(scope),
					Reason:     reason,
					NotTouched: []string{
						filepath.Join(workDir, ".ddx", "executions"),
						filepath.Join(workDir, ".ddx", "agent-logs", "routing-outcomes.jsonl"),
					},
				})
			}

			fmt.Fprintf(out, "adaptive min-tier reset:\n")
			fmt.Fprintf(out, "  state file written: %s\n", statePath)
			fmt.Fprintf(out, "  reset_at:           %s\n", resetAt)
			fmt.Fprintf(out, "  scope:              %s\n", coalesceScope(scope))
			if reason != "" {
				fmt.Fprintf(out, "  reason:             %s\n", reason)
			}
			fmt.Fprintf(out, "  not touched:        %s\n", filepath.Join(workDir, ".ddx", "executions"))
			fmt.Fprintf(out, "                      %s\n", filepath.Join(workDir, ".ddx", "agent-logs", "routing-outcomes.jsonl"))
			fmt.Fprintf(out, "next execute-loop run will re-evaluate cheap tier on its own merits.\n")
			return nil
		},
	}
	cmd.Flags().String("scope", "all", "What to reset: 'cheap' (cheap-tier only) or 'all' (all tiers)")
	cmd.Flags().String("reason", "", "Optional human-readable reason recorded in the state file")
	cmd.Flags().Bool("yes", false, "Skip confirm prompt and apply the reset")
	cmd.Flags().Bool("json", false, "Emit JSON output")
	return cmd
}

func coalesceScope(s string) string {
	if s == "" {
		return "all"
	}
	return s
}

