// buildAdaptiveJSON projects an AdaptiveMinTierResult into the JSON shape
// emitted by `route-status --json` and consumed by tests. Includes the
// effective state-file path so operators know exactly which file the reset
// CLI would touch.
func buildAdaptiveJSON(workingDir string, r escalation.AdaptiveMinTierResult) *routeStatusAdaptiveJSON {
	floor := string(escalation.TierCheap)
	if r.Skipped {
		floor = string(r.Tier)
	}
	tiers := make(map[string]routeStatusTierStatJSON, len(r.PerTier))
	for tier, stats := range r.PerTier {
		tiers[string(tier)] = routeStatusTierStatJSON{
			Attempts:                stats.Attempts,
			Successes:               stats.Successes,
			SuccessRate:             stats.SuccessRate,
			ExcludedRoutingFailures: stats.ExcludedRoutingFailures,
		}
	}
	return &routeStatusAdaptiveJSON{
		Window:                  r.Window,
		Threshold:               escalation.AdaptiveMinTierThreshold,
		MinSamples:              escalation.AdaptiveMinTierMinSamples,
		EffectiveFloor:          floor,
		CheapSkipped:            r.Skipped,
		ResetAt:                 r.ResetAt,
		StateFile:               escalation.AdaptiveStatePath(workingDir),
		ExcludedRoutingFailures: r.ExcludedRoutingFailures,
		Tiers:                   tiers,
	}
}

// renderAdaptiveSection prints the human-readable adaptive min-tier
// diagnostic. The output is designed to answer 'why is cheap being
// skipped' without forcing the operator to read source: it shows the
// trailing window size, attempt count and success rate per tier, the
// configured threshold, the effective floor, whether a reset checkpoint is
// active, and the exact path of the state file.
func renderAdaptiveSection(w io.Writer, r escalation.AdaptiveMinTierResult, stateFile string) {
	fmt.Fprintf(w, "Adaptive Min-Tier Status\n")
	fmt.Fprintf(w, "%s\n", strings.Repeat("-", 70))
	fmt.Fprintf(w, "Window:        %d\n", r.Window)
	fmt.Fprintf(w, "Threshold:     %.2f cheap-tier success rate (min %d samples)\n",
		escalation.AdaptiveMinTierThreshold, escalation.AdaptiveMinTierMinSamples)
	floor := string(escalation.TierCheap)
	if r.Skipped {
		floor = string(r.Tier)
	}
	fmt.Fprintf(w, "Effective floor: %s", floor)
	if r.Skipped {
		fmt.Fprintf(w, "  (cheap tier currently SKIPPED)\n")
	} else {
		fmt.Fprintln(w)
	}
	if r.ResetAt != "" {
		fmt.Fprintf(w, "Reset checkpoint: %s — entries on or before this point are excluded\n", r.ResetAt)
	}
	fmt.Fprintf(w, "State file:    %s\n", stateFile)
	fmt.Fprintf(w, "%-10s %-9s %-10s %-13s %s\n",
		"TIER", "ATTEMPTS", "SUCCESSES", "SUCCESS_RATE", "EXCLUDED_ROUTING")
	for _, tier := range escalation.TierOrder {
		stats := r.PerTier[tier]
		fmt.Fprintf(w, "%-10s %-9d %-10d %-13.2f %d\n",
			string(tier), stats.Attempts, stats.Successes, stats.SuccessRate, stats.ExcludedRoutingFailures)
	}
	fmt.Fprintln(w, "Reset:         ddx agent route-status reset --yes")
}

