// TestAdaptiveMinTierExcludesRoutingFailures verifies AC3: failures whose
// failure_mode classifies them as routing/configuration errors must not
// count against the cheap-tier success rate, because the model never ran.
// A bursty config bug that produces 9 routing-error attempts at cheap tier
// must not condemn cheap tier even after the configuration is fixed.
func TestAdaptiveMinTierExcludesRoutingFailures(t *testing.T) {
	dir := t.TempDir()
	// 9 cheap-tier attempts, all classified as routing errors (e.g. no
	// viable provider, missing API key). These must NOT count toward
	// cheap-tier success rate.
	for i := 0; i < 9; i++ {
		writeAdaptiveFixtureWithMode(t, dir, i, "claude", "claude-haiku-4-5", "task_failed", "routing_error")
	}

	got := AdaptiveMinTier(dir, 50, testResolver)
	assert.Equal(t, TierCheap, got.Tier, "routing failures must not promote min-tier")
	assert.False(t, got.Skipped)
	assert.Equal(t, 0, got.CheapAttempts, "routing-classified attempts are not counted")
	assert.Equal(t, 9, got.ExcludedRoutingFailures)
	assert.Equal(t, 9, got.PerTier[TierCheap].ExcludedRoutingFailures)
}

// TestAdaptiveMinTierMixesGenuineAndRoutingFailures verifies that genuine
// model-execution failures DO count even when interleaved with excluded
// routing failures. The routing failures should not mask a real cheap-tier
// regression.
func TestAdaptiveMinTierMixesGenuineAndRoutingFailures(t *testing.T) {
	dir := t.TempDir()
	// 4 routing failures (excluded) + 4 genuine task_failed (counted) +
	// 1 task_succeeded → counted attempts: 5, success rate 20% (at threshold).
	for i := 0; i < 4; i++ {
		writeAdaptiveFixtureWithMode(t, dir, i, "claude", "claude-haiku-4-5", "task_failed", "routing_error")
	}
	for i := 4; i < 8; i++ {
		writeAdaptiveFixtureWithMode(t, dir, i, "claude", "claude-haiku-4-5", "task_failed", "test_failure")
	}
	writeAdaptiveFixture(t, dir, 8, "claude", "claude-haiku-4-5", "task_succeeded")

	got := AdaptiveMinTier(dir, 50, testResolver)
	assert.Equal(t, 5, got.CheapAttempts)
	assert.Equal(t, 4, got.ExcludedRoutingFailures)
	assert.InDelta(t, 0.20, got.CheapSuccessRate, 0.001)
	assert.Equal(t, TierCheap, got.Tier, "rate at threshold stays cheap")
}

// TestAdaptiveMinTierPopulatesPerTierStats verifies AC2: AdaptiveMinTier
// must report per-tier trailing stats (attempts, successes, success rate)
// so route-status diagnostics can render them without re-walking the
// executions directory.
func TestAdaptiveMinTierPopulatesPerTierStats(t *testing.T) {
	dir := t.TempDir()
	// Cheap: 3 attempts, 1 success
	writeAdaptiveFixture(t, dir, 0, "claude", "claude-haiku-4-5", "task_succeeded")
	writeAdaptiveFixture(t, dir, 1, "claude", "claude-haiku-4-5", "task_failed")
	writeAdaptiveFixture(t, dir, 2, "claude", "claude-haiku-4-5", "task_failed")
	// Standard: 2 attempts, 2 successes
	writeAdaptiveFixture(t, dir, 3, "claude", "claude-sonnet-4-6", "task_succeeded")
	writeAdaptiveFixture(t, dir, 4, "claude", "claude-sonnet-4-6", "task_succeeded")
	// Smart: 1 attempt, 0 successes
	writeAdaptiveFixture(t, dir, 5, "claude", "claude-opus-4-6", "task_failed")

	got := AdaptiveMinTier(dir, 50, testResolver)
	require.NotNil(t, got.PerTier)
	require.Contains(t, got.PerTier, TierCheap)
	require.Contains(t, got.PerTier, TierStandard)
	require.Contains(t, got.PerTier, TierSmart)

	assert.Equal(t, 3, got.PerTier[TierCheap].Attempts)
	assert.Equal(t, 1, got.PerTier[TierCheap].Successes)
	assert.InDelta(t, 1.0/3.0, got.PerTier[TierCheap].SuccessRate, 0.001)

	assert.Equal(t, 2, got.PerTier[TierStandard].Attempts)
	assert.InDelta(t, 1.0, got.PerTier[TierStandard].SuccessRate, 0.001)

	assert.Equal(t, 1, got.PerTier[TierSmart].Attempts)
	assert.InDelta(t, 0.0, got.PerTier[TierSmart].SuccessRate, 0.001)

	assert.Equal(t, 50, got.Window)
}

// TestAdaptiveMinTierResetClearsTrailingWindow verifies AC1, AC5: writing
// a reset checkpoint excludes all prior execution dirs from the trailing
// window, so cheap tier evaluates on its own merits afterward.
func TestAdaptiveMinTierResetClearsTrailingWindow(t *testing.T) {
	dir := t.TempDir()

	// Seed 9 cheap-tier failures — the canonical scenario from the bead
	// description that drives the unresettable 'cheap tier skipped' state.
	for i := 0; i < 9; i++ {
		writeAdaptiveFixture(t, dir, i, "claude", "claude-haiku-4-5", "task_failed")
	}
	got := AdaptiveMinTier(dir, 50, testResolver)
	require.True(t, got.Skipped, "precondition: 9 cheap-tier failures should suppress cheap tier")
	require.Equal(t, TierStandard, got.Tier)

	// Apply the reset: write a checkpoint that sorts above every existing
	// fixture's timestamp prefix so they are all excluded.
	state := AdaptiveState{
		ResetAt:     "20270101T000000-zzzzzzzz",
		ResetBy:     "test",
		ResetReason: "TestAdaptiveMinTierResetClearsTrailingWindow",
	}
	require.NoError(t, WriteAdaptiveState(dir, state))

	got = AdaptiveMinTier(dir, 50, testResolver)
	assert.False(t, got.Skipped, "reset checkpoint must clear the suppressed verdict")
	assert.Equal(t, TierCheap, got.Tier)
	assert.Equal(t, 0, got.CheapAttempts, "all pre-reset attempts must be excluded")
	assert.Equal(t, "20270101T000000-zzzzzzzz", got.ResetAt)

	// New attempts after the reset should count again.
	writeAdaptiveFixtureNamed(t, dir, "20280101T000001-aaaaaaaa", "claude", "claude-haiku-4-5", "task_succeeded")
	got = AdaptiveMinTier(dir, 50, testResolver)
	assert.Equal(t, 1, got.CheapAttempts)
	assert.Equal(t, 1, got.PerTier[TierCheap].Successes)
}

// TestAdaptiveStateRoundTrip exercises the simple read/write helpers that
// back the reset CLI. A missing file must return zero state, not an error.
func TestAdaptiveStateRoundTrip(t *testing.T) {
	dir := t.TempDir()

	got, err := LoadAdaptiveState(dir)
	require.NoError(t, err)
	assert.Equal(t, AdaptiveState{}, got, "missing state file must yield zero value, not error")

	want := AdaptiveState{
		ResetAt:     "20270101T010101-zzzzzzzz",
		ResetBy:     "ddx agent route-status reset",
		ResetReason: "post-incident reset",
	}
	require.NoError(t, WriteAdaptiveState(dir, want))

	got, err = LoadAdaptiveState(dir)
	require.NoError(t, err)
	assert.Equal(t, want, got)

	// State file path is stable and discoverable for documentation.
	assert.Equal(t,
		filepath.Join(dir, ".ddx", "agent-state", "adaptive-min-tier.json"),
		AdaptiveStatePath(dir))
}

