// TestAgentRouteStatusResetClearsState verifies AC1 + AC5 end-to-end via
// the CLI surface. After the reset CLI runs, AdaptiveMinTier must
// re-evaluate from a clean baseline — the prior cheap-tier verdict must
// not carry over.
func TestAgentRouteStatusResetClearsState(t *testing.T) {
	dir := makeProviderTestDir(t, oaiAgentConfig("http://127.0.0.1:9/v1", "x"))

	// Seed the suppression scenario.
	for i := 0; i < 9; i++ {
		ts := fmt.Sprintf("20260101T0004%02d-%08x", i, i)
		writeAdaptiveExecutionFixture(t, dir, ts, "claude", "claude-haiku-4-5", "task_failed", "")
	}

	// Pre-condition: cheap tier suppressed.
	out, err := executeCommand(
		NewCommandFactory(dir).NewRootCommand(),
		"agent", "route-status", "--json",
	)
	require.NoError(t, err)
	var payload routeStatusJSON
	require.NoError(t, json.Unmarshal([]byte(out), &payload))
	require.True(t, payload.AdaptiveMinTier.CheapSkipped, "precondition: 9 failures should suppress")

	// Run reset.
	resetOut, err := executeCommand(
		NewCommandFactory(dir).NewRootCommand(),
		"agent", "route-status", "reset", "--yes",
	)
	require.NoError(t, err)
	require.Contains(t, resetOut, "state file written")
	require.Contains(t, resetOut, "next execute-loop run")

	// State file must exist.
	statePath := filepath.Join(dir, ".ddx", "agent-state", "adaptive-min-tier.json")
	_, statErr := os.Stat(statePath)
	require.NoError(t, statErr, "reset must write %s", statePath)

	// Post-condition: cheap tier no longer suppressed; trailing-window
	// attempts return to zero so a fresh evaluation can proceed.
	out, err = executeCommand(
		NewCommandFactory(dir).NewRootCommand(),
		"agent", "route-status", "--json",
	)
	require.NoError(t, err)
	require.NoError(t, json.Unmarshal([]byte(out), &payload))
	require.False(t, payload.AdaptiveMinTier.CheapSkipped, "reset must clear suppression")
	require.Equal(t, 0, payload.AdaptiveMinTier.Tiers["cheap"].Attempts)
	require.NotEmpty(t, payload.AdaptiveMinTier.ResetAt, "reset checkpoint must surface in diagnostic")
}

